<?php namespace App\Http\Responses; use Illuminate\Http\JsonResponse; use Symfony\Component\HttpFoundation\Response; class ApiResponseFormatter extends JsonResponse { public function __construct($data = null, string $message = '', int $status = Response::HTTP_OK, array $errors = [], array $headers = [], int $options = 0) { $payload = [ 'status' => $status >= 200 && $status < 300, 'message' => $message, 'data' => $data, 'errors' => $errors ]; parent::__construct($payload, $status, $headers, $options); } public static function success($data = null, string $message = 'Operation successful', int $status = Response::HTTP_OK, array $headers = []): self { return new self($data, $message, $status, [], $headers); } public static function error(string $message = 'An error occurred', int $status = Response::HTTP_BAD_REQUEST, array $errors = [], array $headers = []): self { return new self(null, $message, $status, $errors, $headers); } }